{
  "name": "Nasikh AI (ناُسخ)",
  "description": "High-accuracy batch OCR tool optimized for Arabic and English documents. Preserves formatting using Gemini 1.5 Pro."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ProcessingStatus = 'idle' | 'processing' | 'success' | 'error';

export interface ScannedImage {
  id: string;
  file: File;
  previewUrl: string;
  status: ProcessingStatus;
  extractedText: string | null;
  errorMessage?: string;
}

export enum OcrMode {
  Standard = 'STANDARD',
  Formatting = 'FORMATTING', // Preserves tables, lists, etc.
}

import { GoogleGenAI } from "@google/genai";
import { OcrMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Converts a File object to a Base64 string suitable for Gemini API.
 */
const fileToGenerativePart = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove the data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const extractTextFromImage = async (
  file: File, 
  mode: OcrMode
): Promise<string> => {
  try {
    const base64Data = await fileToGenerativePart(file);

    // Prompt engineering based on mode
    let prompt = "Extract all text from this image exactly as it appears. Return only the text.";

    if (mode === OcrMode.Formatting) {
      prompt = `
        You are an advanced OCR engine. 
        Task: Extract all text from this image while strictly preserving the visual structure and formatting.
        Instructions:
        1. Use Markdown to represent headings, lists, bold text, and italics.
        2. If there are tables, represent them as Markdown tables.
        3. Do not summarize or explain. Output ONLY the extracted content.
        4. If the text is in Arabic, ensure proper directionality in your internal reasoning, but output raw Markdown.
        5. Handle multi-column layouts by processing them in logical reading order (usually right-to-left for Arabic).
      `;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // High intelligence model for complex layout understanding
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data
            }
          },
          { text: prompt }
        ]
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No text generated from Gemini.");
    }
    return text;

  } catch (error: any) {
    console.error("Gemini OCR Error:", error);
    throw new Error(error.message || "Failed to process image");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  icon,
  className = '',
  disabled,
  ...props 
}) => {

  const baseStyles = "inline-flex items-center justify-center gap-2 px-4 py-2 rounded-lg font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500 shadow-sm",
    secondary: "bg-white text-slate-700 border border-slate-300 hover:bg-slate-50 focus:ring-slate-400 shadow-sm",
    danger: "bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 focus:ring-red-500",
    ghost: "text-slate-500 hover:text-slate-700 hover:bg-slate-100",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {!isLoading && icon}
      {children}
    </button>
  );
};

import React, { useRef, useState } from 'react';

interface ImageUploaderProps {
  onFilesSelected: (files: File[]) => void;
}

export const ImageUploader: React.FC<ImageUploaderProps> = ({ onFilesSelected }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const validFiles = Array.from(e.dataTransfer.files).filter(file => file.type.startsWith('image/'));
      onFilesSelected(validFiles);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const validFiles = Array.from(e.target.files).filter(file => file.type.startsWith('image/'));
      onFilesSelected(validFiles);
      // Reset input value so same files can be selected again if needed
      e.target.value = '';
    }
  };

  return (
    <div
      onClick={() => fileInputRef.current?.click()}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`
        relative border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors duration-200
        ${isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}
      `}
    >
      <input
        type="file"
        multiple
        accept="image/*"
        ref={fileInputRef}
        className="hidden"
        onChange={handleFileChange}
      />

      <div className="flex flex-col items-center justify-center gap-3">
        <div className="p-3 bg-indigo-100 text-indigo-600 rounded-full">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
            <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 15.75l5.159-5.159a2.25 2.25 0 013.182 0l5.159 5.159m-1.5-1.5l1.409-1.409a2.25 2.25 0 013.182 0l2.909 2.909m-18 3.75h16.5a1.5 1.5 0 001.5-1.5V6a1.5 1.5 0 00-1.5-1.5H3.75A1.5 1.5 0 002.25 6v12a1.5 1.5 0 001.5 1.5zm10.5-11.25h.008v.008h-.008V8.25zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" />
          </svg>
        </div>
        <div>
          <p className="text-lg font-semibold text-slate-700">اضغط للإضافة أو اسحب الصور هنا</p>
          <p className="text-sm text-slate-500 mt-1">يدعم JPG, PNG, WEBP (يمكنك رفع صور متعددة)</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ScannedImage } from '../types';
import { Button } from './Button';

interface ResultViewProps {
  selectedImage: ScannedImage | null;
  onClose: () => void;
}

export const ResultView: React.FC<ResultViewProps> = ({ selectedImage, onClose }) => {
  const [copySuccess, setCopySuccess] = useState(false);

  if (!selectedImage) return null;

  const handleCopy = () => {
    if (selectedImage.extractedText) {
      navigator.clipboard.writeText(selectedImage.extractedText);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    }
  };

  return (
    <div className="absolute inset-0 z-50 bg-slate-50 flex flex-col md:flex-row overflow-hidden animate-fade-in">
      {/* Left (or Right in RTL) Side: Image Preview */}
      <div className="w-full md:w-1/2 bg-slate-900 flex flex-col relative">
         <div className="absolute top-4 left-4 z-10 md:hidden">
            <Button variant="secondary" onClick={onClose} size="sm">إغلاق</Button>
         </div>
        <div className="flex-1 flex items-center justify-center p-6 overflow-hidden">
          <img 
            src={selectedImage.previewUrl} 
            alt="Original" 
            className="max-w-full max-h-full object-contain rounded shadow-lg"
          />
        </div>
        <div className="p-4 bg-slate-800 text-white text-sm text-center">
            {selectedImage.file.name}
        </div>
      </div>

      {/* Content Side: Text Result */}
      <div className="w-full md:w-1/2 flex flex-col h-full border-r border-slate-200 bg-white">
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-slate-100 bg-white shadow-sm">
          <div className="flex items-center gap-2">
             <Button variant="ghost" onClick={onClose} className="hidden md:flex">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                </svg>
             </Button>
             <h2 className="text-lg font-bold text-slate-800">النص المستخرج</h2>
          </div>
          <div className="flex gap-2">
            <Button 
                variant={copySuccess ? "secondary" : "primary"} 
                onClick={handleCopy}
                icon={
                    copySuccess ? (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-green-600" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                        </svg>
                    ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 17.25v3.375c0 .621-.504 1.125-1.125 1.125h-9.75a1.125 1.125 0 01-1.125-1.125V7.875c0-.621.504-1.125 1.125-1.125H6.75a9.06 9.06 0 011.5.124m7.5 10.376h3.375c.621 0 1.125-.504 1.125-1.125V11.25c0-4.46-3.243-8.161-7.5-8.876a9.06 9.06 0 00-1.5-.124H9.375c-.621 0-1.125.504-1.125 1.125v3.5m7.5 10.375H9.375a1.125 1.125 0 01-1.125-1.125v-9.25m12 6.625v-1.875a3.375 3.375 0 00-3.375-3.375h-1.5a1.125 1.125 0 01-1.125-1.125v-1.5a3.375 3.375 0 00-3.375-3.375H9.75" />
                        </svg>
                    )
                }
            >
              {copySuccess ? 'تم النسخ' : 'نسخ النص'}
            </Button>
          </div>
        </div>

        {/* Text Area */}
        <div className="flex-1 overflow-auto p-6 bg-slate-50">
          {selectedImage.status === 'processing' ? (
             <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-4">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
                <p>جاري المعالجة باستخدام الذكاء الاصطناعي...</p>
             </div>
          ) : selectedImage.status === 'error' ? (
             <div className="flex flex-col items-center justify-center h-full text-red-500 gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-12 h-12">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008h-.008v-.008z" />
                </svg>
                <p className="text-center font-semibold">فشل استخراج النص</p>
                <p className="text-sm text-slate-500">{selectedImage.errorMessage}</p>
             </div>
          ) : (
             <div className="prose prose-slate max-w-none prose-p:leading-relaxed prose-headings:text-indigo-900" dir="auto">
                {/* We display raw text in a textarea-like styling for editing, or rendered markdown. 
                    Given user wants to "preserve formatting", a pre-wrap is safest for raw text, 
                    but rendering simple markdown helps visualize tables. 
                    Let's use a simple whitespace-pre-wrap div. 
                */}
                <pre className="whitespace-pre-wrap font-sans text-base text-slate-800">
                    {selectedImage.extractedText}
                </pre>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { ScannedImage, OcrMode } from './types';
import { extractTextFromImage } from './services/geminiService';
import { ImageUploader } from './components/ImageUploader';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';

// Helper to limit concurrency
const CONCURRENCY_LIMIT = 2;

const App: React.FC = () => {
  const [images, setImages] = useState<ScannedImage[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [viewingImageId, setViewingImageId] = useState<string | null>(null);
  const [ocrMode, setOcrMode] = useState<OcrMode>(OcrMode.Formatting);

  // Function to add new files
  const handleFilesSelected = (files: File[]) => {
    const newImages: ScannedImage[] = files.map(file => ({
      id: uuidv4(),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'idle',
      extractedText: null
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const removeImage = (id: string) => {
    setImages(prev => {
      const img = prev.find(i => i.id === id);
      if (img) URL.revokeObjectURL(img.previewUrl);
      return prev.filter(i => i.id !== id);
    });
    if (viewingImageId === id) setViewingImageId(null);
  };

  // Processing Queue Logic
  useEffect(() => {
    if (!isProcessing) return;

    const processNextBatch = async () => {
      // Find images that are processing
      const activeCount = images.filter(img => img.status === 'processing').length;

      // Find next idle images
      const pendingImages = images.filter(img => img.status === 'idle');

      if (activeCount === 0 && pendingImages.length === 0) {
        setIsProcessing(false);
        return;
      }

      if (activeCount < CONCURRENCY_LIMIT && pendingImages.length > 0) {
        const slotsAvailable = CONCURRENCY_LIMIT - activeCount;
        const batch = pendingImages.slice(0, slotsAvailable);

        // Mark as processing immediately to prevent duplicate pick-up
        setImages(prev => prev.map(img => 
          batch.some(b => b.id === img.id) ? { ...img, status: 'processing' } : img
        ));

        // Process batch in parallel
        batch.forEach(async (image) => {
          try {
            const text = await extractTextFromImage(image.file, ocrMode);
            setImages(prev => prev.map(img => 
              img.id === image.id ? { ...img, status: 'success', extractedText: text } : img
            ));
          } catch (error: any) {
            setImages(prev => prev.map(img => 
              img.id === image.id ? { ...img, status: 'error', errorMessage: error.message } : img
            ));
          }
        });
      }
    };

    const interval = setInterval(processNextBatch, 500); // Check queue every 500ms
    return () => clearInterval(interval);
  }, [images, isProcessing, ocrMode]);

  const startProcessing = () => {
    setIsProcessing(true);
  };

  const clearAll = () => {
      // revoke urls
      images.forEach(img => URL.revokeObjectURL(img.previewUrl));
      setImages([]);
      setViewingImageId(null);
      setIsProcessing(false);
  }

  const viewingImage = images.find(img => img.id === viewingImageId) || null;
  const stats = {
      total: images.length,
      completed: images.filter(i => i.status === 'success').length,
      failed: images.filter(i => i.status === 'error').length,
      pending: images.filter(i => i.status === 'idle' || i.status === 'processing').length
  }

  return (
    <div className="flex h-full bg-slate-50">

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">

        {/* Header */}
        <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-indigo-200 shadow-lg">
                ن
            </div>
            <div>
                <h1 className="text-xl font-bold text-slate-800">ناسخ الذكي (Nasikh AI)</h1>
                <p className="text-xs text-slate-500">تحويل الصور لنص مع الحفاظ على التنسيق</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {/* Mode Toggle */}
             <div className="hidden md:flex bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setOcrMode(OcrMode.Formatting)}
                    className={`px-3 py-1 text-sm rounded-md transition-all ${ocrMode === OcrMode.Formatting ? 'bg-white shadow text-indigo-600 font-medium' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    تنسيق ذكي
                </button>
                <button 
                    onClick={() => setOcrMode(OcrMode.Standard)}
                    className={`px-3 py-1 text-sm rounded-md transition-all ${ocrMode === OcrMode.Standard ? 'bg-white shadow text-indigo-600 font-medium' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    نص عادي
                </button>
             </div>

             {stats.total > 0 && (
                 <div className="text-sm font-medium text-slate-600">
                    {stats.completed}/{stats.total} مكتمل
                 </div>
             )}
          </div>
        </header>

        {/* Scrollable Body */}
        <main className="flex-1 overflow-y-auto p-6 md:p-8">
            <div className="max-w-6xl mx-auto space-y-8">

                {/* Action Area */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                    <ImageUploader onFilesSelected={handleFilesSelected} />

                    {stats.total > 0 && (
                        <div className="flex items-center justify-between mt-6 pt-6 border-t border-slate-100 animate-fade-in">
                            <div className="text-sm text-slate-500">
                                {stats.total} ملفات جاهزة للمعالجة
                            </div>
                            <div className="flex gap-3">
                                <Button variant="secondary" onClick={clearAll} disabled={isProcessing}>
                                    مسح الكل
                                </Button>
                                <Button 
                                    onClick={startProcessing} 
                                    isLoading={isProcessing && stats.pending > 0}
                                    disabled={stats.pending === 0}
                                    icon={
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 13.5l10.5-11.25L12 10.5h8.25L9.75 21.75 12 13.5H3.75z" />
                                        </svg>
                                    }
                                >
                                    {isProcessing ? 'جاري المعالجة...' : 'بدء التحويل'}
                                </Button>
                            </div>
                        </div>
                    )}
                </div>

                {/* Grid */}
                {stats.total > 0 && (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
                        {images.map((img) => (
                            <div 
                                key={img.id} 
                                onClick={() => setViewingImageId(img.id)}
                                className={`
                                    group relative bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden cursor-pointer transition-all hover:shadow-md
                                    ${img.status === 'processing' ? 'ring-2 ring-indigo-500 ring-offset-2' : ''}
                                    ${img.status === 'success' ? 'border-green-200' : ''}
                                    ${img.status === 'error' ? 'border-red-200' : ''}
                                `}
                            >
                                {/* Remove Button */}
                                <button 
                                    onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                                    className="absolute top-2 left-2 z-10 bg-white/80 hover:bg-red-50 text-slate-400 hover:text-red-500 p-1.5 rounded-full backdrop-blur-sm transition-colors opacity-0 group-hover:opacity-100"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                                        <path d="M6.28 5.22a.75.75 0 00-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 101.06 1.06L10 11.06l3.72 3.72a.75.75 0 101.06-1.06L11.06 10l3.72-3.72a.75.75 0 00-1.06-1.06L10 8.94 6.28 5.22z" />
                                    </svg>
                                </button>

                                {/* Image Aspect Ratio Box */}
                                <div className="aspect-[3/2] w-full bg-slate-100 relative overflow-hidden">
                                    <img src={img.previewUrl} alt="preview" className="w-full h-full object-cover" />

                                    {/* Overlay Status */}
                                    <div className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/10 transition-colors">
                                        {img.status === 'processing' && (
                                            <div className="bg-white/90 p-2 rounded-full shadow-lg">
                                                 <svg className="animate-spin h-6 w-6 text-indigo-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                                </svg>
                                            </div>
                                        )}
                                        {img.status === 'success' && (
                                             <div className="bg-green-500/90 text-white p-2 rounded-full shadow-lg">
                                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-6 h-6">
                                                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                                </svg>
                                            </div>
                                        )}
                                        {img.status === 'error' && (
                                             <div className="bg-red-500/90 text-white p-2 rounded-full shadow-lg">
                                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-6 h-6">
                                                    <path d="M6.28 5.22a.75.75 0 00-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 101.06 1.06L10 11.06l3.72 3.72a.75.75 0 101.06-1.06L11.06 10l3.72-3.72a.75.75 0 00-1.06-1.06L10 8.94 6.28 5.22z" />
                                                </svg>
                                            </div>
                                        )}
                                    </div>
                                </div>

                                {/* Footer info */}
                                <div className="p-3">
                                    <p className="text-sm font-medium text-slate-700 truncate text-right">{img.file.name}</p>
                                    <div className="flex justify-between items-center mt-2">
                                        <span className={`text-xs font-semibold px-2 py-0.5 rounded-full 
                                            ${img.status === 'idle' ? 'bg-slate-100 text-slate-500' : ''}
                                            ${img.status === 'processing' ? 'bg-indigo-50 text-indigo-600' : ''}
                                            ${img.status === 'success' ? 'bg-green-50 text-green-700' : ''}
                                            ${img.status === 'error' ? 'bg-red-50 text-red-600' : ''}
                                        `}>
                                            {img.status === 'idle' && 'قيد الانتظار'}
                                            {img.status === 'processing' && 'جاري التحويل'}
                                            {img.status === 'success' && 'تم بنجاح'}
                                            {img.status === 'error' && 'فشل'}
                                        </span>
                                        {img.status === 'success' && (
                                            <span className="text-xs text-indigo-600 font-medium">عرض النتائج &larr;</span>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </main>

        {/* Modal/Overlay for results */}
        {viewingImage && (
            <ResultView 
                selectedImage={viewingImage} 
                onClose={() => setViewingImageId(null)} 
            />
        )}

      </div>
    </div>
  );
};

export default App;

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md',
  isLoading, 
  icon,
  className = '',
  disabled,
  ...props 
}) => {

  const baseStyles = "inline-flex items-center justify-center gap-2 rounded-lg font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500 shadow-sm",
    secondary: "bg-white text-slate-700 border border-slate-300 hover:bg-slate-50 focus:ring-slate-400 shadow-sm",
    danger: "bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 focus:ring-red-500",
    ghost: "text-slate-500 hover:text-slate-700 hover:bg-slate-100",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-4 py-2",
    lg: "px-6 py-3 text-lg",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {!isLoading && icon}
      {children}
    </button>
  );
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Document, Packer, Paragraph, TextRun, PageBreak, AlignmentType, HeadingLevel } from "docx";
import { saveAs } from "file-saver";
import { ScannedImage, OcrMode } from './types';
import { extractTextFromImage } from './services/geminiService';
import { ImageUploader } from './components/ImageUploader';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';

// Helper to limit concurrency
const CONCURRENCY_LIMIT = 2;

const App: React.FC = () => {
  const [images, setImages] = useState<ScannedImage[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [viewingImageId, setViewingImageId] = useState<string | null>(null);
  const [ocrMode, setOcrMode] = useState<OcrMode>(OcrMode.Formatting);

  // Drag and Drop State
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Function to add new files
  const handleFilesSelected = (files: File[]) => {
    const newImages: ScannedImage[] = files.map(file => ({
      id: uuidv4(),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'idle',
      extractedText: null
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const removeImage = (id: string) => {
    setImages(prev => {
      const img = prev.find(i => i.id === id);
      if (img) URL.revokeObjectURL(img.previewUrl);
      return prev.filter(i => i.id !== id);
    });
    if (viewingImageId === id) setViewingImageId(null);
  };

  // Processing Queue Logic
  useEffect(() => {
    if (!isProcessing) return;

    const processNextBatch = async () => {
      // Find images that are processing
      const activeCount = images.filter(img => img.status === 'processing').length;

      // Find next idle images
      const pendingImages = images.filter(img => img.status === 'idle');

      if (activeCount === 0 && pendingImages.length === 0) {
        setIsProcessing(false);
        return;
      }

      if (activeCount < CONCURRENCY_LIMIT && pendingImages.length > 0) {
        const slotsAvailable = CONCURRENCY_LIMIT - activeCount;
        const batch = pendingImages.slice(0, slotsAvailable);

        // Mark as processing immediately to prevent duplicate pick-up
        setImages(prev => prev.map(img => 
          batch.some(b => b.id === img.id) ? { ...img, status: 'processing' } : img
        ));

        // Process batch in parallel
        batch.forEach(async (image) => {
          try {
            const text = await extractTextFromImage(image.file, ocrMode);
            setImages(prev => prev.map(img => 
              img.id === image.id ? { ...img, status: 'success', extractedText: text } : img
            ));
          } catch (error: any) {
            setImages(prev => prev.map(img => 
              img.id === image.id ? { ...img, status: 'error', errorMessage: error.message } : img
            ));
          }
        });
      }
    };

    const interval = setInterval(processNextBatch, 500); // Check queue every 500ms
    return () => clearInterval(interval);
  }, [images, isProcessing, ocrMode]);

  const startProcessing = () => {
    setIsProcessing(true);
  };

  const clearAll = () => {
      // revoke urls
      images.forEach(img => URL.revokeObjectURL(img.previewUrl));
      setImages([]);
      setViewingImageId(null);
      setIsProcessing(false);
  }

  // --- Sorting & DnD Handlers ---

  const handleSortByName = () => {
    setImages(prev => [...prev].sort((a, b) => a.file.name.localeCompare(b.file.name)));
  };

  const handleDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    setIsDragging(true);
    // Setting ghost image effect if needed, usually browser handles it
    // e.dataTransfer.effectAllowed = "move";
  };

  const handleDragEnter = (e: React.DragEvent, index: number) => {
    dragOverItem.current = index;
    // We can add a visual class here if we used state for dragOverIndex, 
    // but for performance we keep it simple or use CSS :hover logic combined with drag state
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
        const _images = [...images];
        const draggedItemContent = _images[dragItem.current];
        _images.splice(dragItem.current, 1);
        _images.splice(dragOverItem.current, 0, draggedItemContent);
        setImages(_images);
    }
    dragItem.current = null;
    dragOverItem.current = null;
    setIsDragging(false);
  };

  // --- Export Handler ---

  const handleExportDocx = async () => {
    const completedImages = images.filter(img => img.status === 'success' && img.extractedText);

    if (completedImages.length === 0) {
        alert("لا يوجد نصوص مكتملة للتصدير. يرجى الانتظار حتى انتهاء المعالجة.");
        return;
    }

    try {
        const docChildren: any[] = [];

        completedImages.forEach((img, index) => {
            // Add page break if not first
            if (index > 0) {
                docChildren.push(new Paragraph({ children: [new PageBreak()] }));
            }

            // Add a separator/title for the page (Optional, but good for merged docs)
            docChildren.push(new Paragraph({
                 text: `--- ${img.file.name} ---`,
                 alignment: AlignmentType.CENTER,
                 heading: HeadingLevel.HEADING_3,
                 spacing: { after: 200, before: 200 },
                 bidirectional: true
            }));

            // Simple Markdown-ish parser to preservation basic structure
            const lines = (img.extractedText || "").split('\n');

            lines.forEach(line => {
                 const trimmed = line.trim();
                 if (!trimmed) {
                     // Empty line -> Spacing
                     docChildren.push(new Paragraph({ text: "" }));
                     return;
                 }

                 let headingLevel: typeof HeadingLevel[keyof typeof HeadingLevel] | undefined = undefined;
                 let text = trimmed;

                 // Basic Header detection
                 if (trimmed.startsWith('# ')) {
                     headingLevel = HeadingLevel.HEADING_1;
                     text = trimmed.substring(2);
                 } else if (trimmed.startsWith('## ')) {
                     headingLevel = HeadingLevel.HEADING_2;
                     text = trimmed.substring(3);
                 } else if (trimmed.startsWith('### ')) {
                     headingLevel = HeadingLevel.HEADING_3;
                     text = trimmed.substring(4);
                 }

                 docChildren.push(new Paragraph({
                     children: [new TextRun({ 
                         text: text, 
                         size: 24, // 12pt
                         font: "Arial" // Good for Arabic
                     })],
                     heading: headingLevel,
                     bidirectional: true,
                     alignment: AlignmentType.RIGHT // Default to RTL for Arabic context
                 }));
            });
        });

        const doc = new Document({
            sections: [{
                properties: {},
                children: docChildren,
            }],
        });

        const blob = await Packer.toBlob(doc);
        saveAs(blob, "Nasikh_Combined_Output.docx");

    } catch (e) {
        console.error("Export failed", e);
        alert("فشل إنشاء ملف الورد. يرجى المحاولة مرة أخرى.");
    }
  };

  const viewingImage = images.find(img => img.id === viewingImageId) || null;
  const stats = {
      total: images.length,
      completed: images.filter(i => i.status === 'success').length,
      failed: images.filter(i => i.status === 'error').length,
      pending: images.filter(i => i.status === 'idle' || i.status === 'processing').length
  }

  return (
    <div className="flex h-full bg-slate-50">

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">

        {/* Header */}
        <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-indigo-200 shadow-lg">
                ن
            </div>
            <div>
                <h1 className="text-xl font-bold text-slate-800">ناسخ الذكي (Nasikh AI)</h1>
                <p className="text-xs text-slate-500">تحويل الصور لنص مع الحفاظ على التنسيق</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {/* Mode Toggle */}
             <div className="hidden md:flex bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setOcrMode(OcrMode.Formatting)}
                    className={`px-3 py-1 text-sm rounded-md transition-all ${ocrMode === OcrMode.Formatting ? 'bg-white shadow text-indigo-600 font-medium' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    تنسيق ذكي
                </button>
                <button 
                    onClick={() => setOcrMode(OcrMode.Standard)}
                    className={`px-3 py-1 text-sm rounded-md transition-all ${ocrMode === OcrMode.Standard ? 'bg-white shadow text-indigo-600 font-medium' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    نص عادي
                </button>
             </div>

             {stats.total > 0 && (
                 <div className="text-sm font-medium text-slate-600">
                    {stats.completed}/{stats.total} مكتمل
                 </div>
             )}
          </div>
        </header>

        {/* Scrollable Body */}
        <main className="flex-1 overflow-y-auto p-6 md:p-8">
            <div className="max-w-6xl mx-auto space-y-8">

                {/* Action Area */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                    <ImageUploader onFilesSelected={handleFilesSelected} />

                    {stats.total > 0 && (
                        <div className="flex flex-col md:flex-row items-center justify-between mt-6 pt-6 border-t border-slate-100 animate-fade-in gap-4">
                            <div className="flex items-center gap-3 w-full md:w-auto">
                                <Button variant="secondary" onClick={handleSortByName} title="ترتيب الصور أبجدياً حسب اسم الملف" icon={
                                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                      <path strokeLinecap="round" strokeLinejoin="round" d="M3 7.5L7.5 3m0 0L12 7.5M7.5 3v13.5m13.5 0L16.5 21m0 0L12 16.5m4.5 4.5V7.5" />
                                    </svg>
                                }>
                                    ترتيب بالاسم
                                </Button>
                                <div className="text-sm text-slate-500 hidden md:block">
                                    {stats.total} ملفات (اسحب لتغيير الترتيب)
                                </div>
                            </div>

                            <div className="flex gap-3 w-full md:w-auto justify-end">
                                <Button variant="ghost" onClick={clearAll} disabled={isProcessing}>
                                    مسح الكل
                                </Button>

                                <Button 
                                    variant="secondary"
                                    onClick={handleExportDocx}
                                    disabled={stats.completed === 0}
                                    title="تحميل جميع النصوص المستخرجة في ملف وورد واحد"
                                    icon={
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-blue-600">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m2.25 0H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
                                        </svg>
                                    }
                                >
                                    تصدير DOCX
                                </Button>

                                <Button 
                                    onClick={startProcessing} 
                                    isLoading={isProcessing && stats.pending > 0}
                                    disabled={stats.pending === 0}
                                    icon={
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 13.5l10.5-11.25L12 10.5h8.25L9.75 21.75 12 13.5H3.75z" />
                                        </svg>
                                    }
                                >
                                    {isProcessing ? 'جاري المعالجة...' : 'بدء التحويل'}
                                </Button>
                            </div>
                        </div>
                    )}
                </div>

                {/* Grid */}
                {stats.total > 0 && (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
                        {images.map((img, index) => (
                            <div 
                                key={img.id} 
                                draggable
                                onDragStart={(e) => handleDragStart(e, index)}
                                onDragEnter={(e) => handleDragEnter(e, index)}
                                onDragEnd={handleDragEnd}
                                onDragOver={(e) => e.preventDefault()} // Necessary for drop to work
                                onClick={() => setViewingImageId(img.id)}
                                className={`
                                    group relative bg-white rounded-xl shadow-sm border overflow-hidden cursor-pointer transition-all hover:shadow-md select-none
                                    ${img.status === 'processing' ? 'ring-2 ring-indigo-500 ring-offset-2 border-indigo-500' : 'border-slate-200'}
                                    ${img.status === 'success' ? 'border-green-200' : ''}
                                    ${img.status === 'error' ? 'border-red-200' : ''}
                                    active:cursor-grabbing hover:scale-[1.01] transition-transform duration-200
                                `}
                            >
                                {/* Drag Handle Indicator (Visual cue) */}
                                <div className="absolute top-2 right-2 z-10 p-1.5 bg-black/20 text-white rounded-md opacity-0 group-hover:opacity-100 cursor-grab">
                                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                      <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 6.75h16.5M3.75 12h16.5m-16.5 5.25h16.5" />
                                    </svg>
                                </div>

                                {/* Remove Button */}
                                <button 
                                    onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                                    className="absolute top-2 left-2 z-10 bg-white/80 hover:bg-red-50 text-slate-400 hover:text-red-500 p-1.5 rounded-full backdrop-blur-sm transition-colors opacity-0 group-hover:opacity-100"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                                        <path d="M6.28 5.22a.75.75 0 00-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 101.06 1.06L10 11.06l3.72 3.72a.75.75 0 101.06-1.06L11.06 10l3.72-3.72a.75.75 0 00-1.06-1.06L10 8.94 6.28 5.22z" />
                                    </svg>
                                </button>

                                {/* Order Badge */}
                                <div className="absolute bottom-2 left-2 z-10 bg-slate-900/50 text-white text-[10px] px-1.5 py-0.5 rounded backdrop-blur-sm">
                                    #{index + 1}
                                </div>

                                {/* Image Aspect Ratio Box */}
                                <div className="aspect-[3/2] w-full bg-slate-100 relative overflow-hidden">
                                    <img src={img.previewUrl} alt="preview" className="w-full h-full object-cover pointer-events-none" />

                                    {/* Overlay Status */}
                                    <div className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/10 transition-colors">
                                        {img.status === 'processing' && (
                                            <div className="bg-white/90 p-2 rounded-full shadow-lg">
                                                 <svg className="animate-spin h-6 w-6 text-indigo-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                                </svg>
                                            </div>
                                        )}
                                        {img.status === 'success' && (
                                             <div className="bg-green-500/90 text-white p-2 rounded-full shadow-lg">
                                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-6 h-6">
                                                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                                                </svg>
                                            </div>
                                        )}
                                        {img.status === 'error' && (
                                             <div className="bg-red-500/90 text-white p-2 rounded-full shadow-lg">
                                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-6 h-6">
                                                    <path d="M6.28 5.22a.75.75 0 00-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 101.06 1.06L10 11.06l3.72 3.72a.75.75 0 101.06-1.06L11.06 10l3.72-3.72a.75.75 0 00-1.06-1.06L10 8.94 6.28 5.22z" />
                                                </svg>
                                            </div>
                                        )}
                                    </div>
                                </div>

                                {/* Footer info */}
                                <div className="p-3">
                                    <p className="text-sm font-medium text-slate-700 truncate text-right" dir="ltr">{img.file.name}</p>
                                    <div className="flex justify-between items-center mt-2">
                                        <span className={`text-xs font-semibold px-2 py-0.5 rounded-full 
                                            ${img.status === 'idle' ? 'bg-slate-100 text-slate-500' : ''}
                                            ${img.status === 'processing' ? 'bg-indigo-50 text-indigo-600' : ''}
                                            ${img.status === 'success' ? 'bg-green-50 text-green-700' : ''}
                                            ${img.status === 'error' ? 'bg-red-50 text-red-600' : ''}
                                        `}>
                                            {img.status === 'idle' && 'قيد الانتظار'}
                                            {img.status === 'processing' && 'جاري التحويل'}
                                            {img.status === 'success' && 'تم بنجاح'}
                                            {img.status === 'error' && 'فشل'}
                                        </span>
                                        {img.status === 'success' && (
                                            <span className="text-xs text-indigo-600 font-medium">عرض &larr;</span>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </main>

        {/* Modal/Overlay for results */}
        {viewingImage && (
            <ResultView 
                selectedImage={viewingImage} 
                onClose={() => setViewingImageId(null)} 
            />
        )}

      </div>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';

interface ImageUploaderProps {
  onFilesSelected: (files: File[]) => void;
}

export const ImageUploader: React.FC<ImageUploaderProps> = ({ onFilesSelected }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const validFiles = Array.from(e.dataTransfer.files).filter((file: File) => file.type.startsWith('image/'));
      onFilesSelected(validFiles);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const validFiles = Array.from(e.target.files).filter((file: File) => file.type.startsWith('image/'));
      onFilesSelected(validFiles);
      // Reset input value so same files can be selected again if needed
      e.target.value = '';
    }
  };

  return (
    <div
      onClick={() => fileInputRef.current?.click()}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`
        relative border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors duration-200
        ${isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}
      `}
    >
      <input
        type="file"
        multiple
        accept="image/*"
        ref={fileInputRef}
        className="hidden"
        onChange={handleFileChange}
      />

      <div className="flex flex-col items-center justify-center gap-3">
        <div className="p-3 bg-indigo-100 text-indigo-600 rounded-full">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-8 h-8">
            <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 15.75l5.159-5.159a2.25 2.25 0 013.182 0l5.159 5.159m-1.5-1.5l1.409-1.409a2.25 2.25 0 013.182 0l2.909 2.909m-18 3.75h16.5a1.5 1.5 0 001.5-1.5V6a1.5 1.5 0 00-1.5-1.5H3.75A1.5 1.5 0 002.25 6v12a1.5 1.5 0 001.5 1.5zm10.5-11.25h.008v.008h-.008V8.25zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" />
          </svg>
        </div>
        <div>
          <p className="text-lg font-semibold text-slate-700">اضغط للإضافة أو اسحب الصور هنا</p>
          <p className="text-sm text-slate-500 mt-1">يدعم JPG, PNG, WEBP (يمكنك رفع صور متعددة)</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Document, Packer, Paragraph, TextRun, PageBreak, AlignmentType, HeadingLevel } from "docx";
import saveAs from "file-saver";
import { ScannedImage, OcrMode } from './types';
import { extractTextFromImage } from './services/geminiService';
import { ImageUploader } from './components/ImageUploader';
import { Button } from './components/Button';
import { ResultView } from './components/ResultView';

// Helper to limit concurrency
const CONCURRENCY_LIMIT = 2;

const App: React.FC = () => {
  const [images, setImages] = useState<ScannedImage[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [viewingImageId, setViewingImageId] = useState<string | null>(null);
  const [ocrMode, setOcrMode] = useState<OcrMode>(OcrMode.Formatting);

  // Drag and Drop State
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Function to add new files
  const handleFilesSelected = (files: File[]) => {
    const newImages: ScannedImage[] = files.map(file => ({
      id: uuidv4(),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'idle',
      extractedText: null
    }));
    setImages(prev => [...prev, ...newImages]);
  };

  const removeImage = (id: string) => {
    setImages(prev => {
      const img = prev.find(i => i.id === id);
      if (img) URL.revokeObjectURL(img.previewUrl);
      return prev.filter(i => i.id !== id);
    });
    if (viewingImageId === id) setViewingImageId(null);
  };

  // Processing Queue Logic
  useEffect(() => {
    if (!isProcessing) return;

    const processNextBatch = async () => {
      // Find images that are processing
      const activeCount = images.filter(img => img.status === 'processing').length;

      // Find next idle images
      const pendingImages = images.filter(img => img.status === 'idle');

      if (activeCount === 0 && pendingImages.length === 0) {
        setIsProcessing(false);
        return;
      }

      if (activeCount < CONCURRENCY_LIMIT && pendingImages.length > 0) {
        const slotsAvailable = CONCURRENCY_LIMIT - activeCount;
        const batch = pendingImages.slice(0, slotsAvailable);

        // Mark as processing immediately to prevent duplicate pick-up
        setImages(prev => prev.map(img => 
          batch.some(b => b.id === img.id) ? { ...img, status: 'processing' } : img
        ));

        // Process batch in parallel
        batch.forEach(async (image) => {
          try {
            const text = await extractTextFromImage(image.file, ocrMode);
            setImages(prev => prev.map(img => 
              img.id === image.id ? { ...img, status: 'success', extractedText: text } : img
            ));
          } catch (error: any) {
            setImages(prev => prev.map(img => 
              img.id === image.id ? { ...img, status: 'error', errorMessage: error.message } : img
            ));
          }
        });
      }
    };

    const interval = setInterval(processNextBatch, 500); // Check queue every 500ms
    return () => clearInterval(interval);
  }, [images, isProcessing, ocrMode]);

  const startProcessing = () => {
    setIsProcessing(true);
  };

  const clearAll = () => {
      // revoke urls
      images.forEach(img => URL.revokeObjectURL(img.previewUrl));
      setImages([]);
      setViewingImageId(null);
      setIsProcessing(false);
  }

  // --- Sorting & DnD Handlers ---

  const handleSortByName = () => {
    setImages(prev => [...prev].sort((a, b) => a.file.name.localeCompare(b.file.name)));
  };

  const handleDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
    setIsDragging(true);
    // Setting ghost image effect if needed, usually browser handles it
    // e.dataTransfer.effectAllowed = "move";
  };

  const handleDragEnter = (e: React.DragEvent, index: number) => {
    dragOverItem.current = index;
    // We can add a visual class here if we used state for dragOverIndex, 
    // but for performance we keep it simple or use CSS :hover logic combined with drag state
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
        const _images = [...images];
        const draggedItemContent = _images[dragItem.current];
        _images.splice(dragItem.current, 1);
        _images.splice(dragOverItem.current, 0, draggedItemContent);
        setImages(_images);
    }
    dragItem.current = null;
    dragOverItem.current = null;
    setIsDragging(false);
  };

  // --- Export Handler ---

  const handleExportDocx = async () => {
    const completedImages = images.filter(img => img.status === 'success' && img.extractedText);

    if (completedImages.length === 0) {
        alert("لا يوجد نصوص مكتملة للتصدير. يرجى الانتظار حتى انتهاء المعالجة.");
        return;
    }

    try {
        const docChildren: any[] = [];

        completedImages.forEach((img, index) => {
            // Add page break if not first
            if (index > 0) {
                docChildren.push(new Paragraph({ children: [new PageBreak()] }));
            }

            // Add a separator/title for the page (Optional, but good for merged docs)
            docChildren.push(new Paragraph({
                 text: `--- ${img.file.name} ---`,
                 alignment: AlignmentType.CENTER,
                 heading: HeadingLevel.HEADING_3,
                 spacing: { after: 200, before: 200 },
                 bidirectional: true
            }));

            // Simple Markdown-ish parser to preservation basic structure
            const lines = (img.extractedText || "").split('\n');

            lines.forEach(line => {
                 const trimmed = line.trim();
                 if (!trimmed) {
                     // Empty line -> Spacing
                     docChildren.push(new Paragraph({ text: "" }));
                     return;
                 }

                 let headingLevel: typeof HeadingLevel[keyof typeof HeadingLevel] | undefined = undefined;
                 let text = trimmed;

                 // Basic Header detection
                 if (trimmed.startsWith('# ')) {
                     headingLevel = HeadingLevel.HEADING_1;
                     text = trimmed.substring(2);
                 } else if (trimmed.startsWith('## ')) {
                     headingLevel = HeadingLevel.HEADING_2;
                     text = trimmed.substring(3);
                 } else if (trimmed.startsWith('### ')) {
                     headingLevel = HeadingLevel.HEADING_3;
                     text = trimmed.substring(4);
                 }

                 docChildren.push(new Paragraph({
                     children: [new TextRun({ 
                         text: text, 
                         size: 24, // 12pt
                         font: "Arial" // Good for Arabic
                     })],
                     heading: headingLevel,
                     bidirectional: true,
                     alignment: AlignmentType.RIGHT // Default to RTL for Arabic context
                 }));
            });
        });

        const doc = new Document({
            sections: [{
                properties: {},
                children: docChildren,
            }],
        });

        const blob = await Packer.toBlob(doc);
        saveAs(blob, "Nasikh_Combined_Output.docx");

    } catch (e) {
        console.error("Export failed", e);
        alert("فشل إنشاء ملف الورد. يرجى المحاولة مرة أخرى.");
    }
  };

  const viewingImage = images.find(img => img.id === viewingImageId) || null;
  const stats = {
      total: images.length,
      completed: images.filter(i => i.status === 'success').length,
      failed: images.filter(i => i.status === 'error').length,
      pending: images.filter(i => i.status === 'idle' || i.status === 'processing').length
  }

  return (
    <div className="flex h-full bg-slate-50">

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">

        {/* Header */}
        <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm z-10">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-indigo-200 shadow-lg">
                ن
            </div>
            <div>
                <h1 className="text-xl font-bold text-slate-800">ناسخ الذكي (Nasikh AI)</h1>
                <p className="text-xs text-slate-500">تحويل الصور لنص مع الحفاظ على التنسيق</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {/* Mode Toggle */}
             <div className="hidden md:flex bg-slate-100 p-1 rounded-lg">
                <button 
                    onClick={() => setOcrMode(OcrMode.Formatting)}
                    className={`px-3 py-1 text-sm rounded-md transition-all ${ocrMode === OcrMode.Formatting ? 'bg-white shadow text-indigo-600 font-medium' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    تنسيق ذكي
                </button>
                <button 
                    onClick={() => setOcrMode(OcrMode.Standard)}
                    className={`px-3 py-1 text-sm rounded-md transition-all ${ocrMode === OcrMode.Standard ? 'bg-white shadow text-indigo-600 font-medium' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    نص عادي
                </button>
             </div>

             {stats.total > 0 && (
                 <div className="text-sm font-medium text-slate-600">
                    {stats.completed}/{stats.total} مكتمل
                 </div>
             )}
          </div>
        </header>

        {/* Scrollable Body */}
        <main className="flex-1 overflow-y-auto p-6 md:p-8">
            <div className="max-w-6xl mx-auto space-y-8">

                {/* Action Area */}
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
                    <ImageUploader onFilesSelected={handleFilesSelected} />

                    {stats.total > 0 && (
                        <div className="flex flex-col md:flex-row items-center justify-between mt-6 pt-6 border-t border-slate-100 animate-fade-in gap-4">
                            <div className="flex items-center gap-3 w-full md:w-auto">
                                <Button variant="secondary" onClick={handleSortByName} title="ترتيب الصور أبجدياً حسب اسم الملف" icon={
                                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                      <path strokeLinecap="round" strokeLinejoin="round" d="M3 7.5L7.5 3m0 0L12 7.5M7.5 3v13.5m13.5 0L16.5 21m0 0L12 16.5m4.5 4.5V7.5" />
                                    </svg>
                                }>
                                    ترتيب بالاسم
                                </Button>
                                <div className="text-sm text-slate-500 hidden md:block">
                                    {stats.total} ملفات (اسحب لتغيير الترتيب)
                                </div>
                            </div>

                            <div className="flex gap-3 w-full md:w-auto justify-end">
                                <Button variant="ghost" onClick={clearAll} disabled={isProcessing}>
                                    مسح الكل
                                </Button>

                                <Button 
                                    variant="secondary"
                                    onClick={handleExportDocx}
                                    disabled={stats.completed === 0}
                                    title="تحميل جميع النصوص المستخرجة في ملف وورد واحد"
                                    icon={
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 text-blue-600">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m2.25 0H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
                                        </svg>
                                    }
                                >
                                    تصدير DOCX
                                </Button>

                                <Button 
                                    onClick={startProcessing} 
                                    isLoading={isProcessing && stats.pending > 0}
                                    disabled={stats.pending === 0}
                                    icon={
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 13.5l10.5-11.25L12 10.5h8.25L9.75 21.75 12 13.5H3.75z" />
                                        </svg>
                                    }
                                >
                                    {isProcessing ? 'جاري المعالجة...' : 'بدء التحويل'}
                                </Button>
                            </div>
                        </div>
                    )}
                </div>

                {/* Grid */}
                {stats.total > 0 && (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
                        {images.map((img, index) => (
                            <div 
                                key={img.id} 
                                draggable
                                onDragStart={(e) => handleDragStart(e, index)}
                                onDragEnter={(e) => handleDragEnter(e, index)}
                                onDragEnd={handleDragEnd}
                                onDragOver={(e) => e.preventDefault()} // Necessary for drop to work
                                onClick={() => setViewingImageId(img.id)}
                                className={`
                                    group relative bg-white rounded-xl shadow-sm border overflow-hidden cursor-pointer transition-all hover:shadow-md select-none
                                    ${img.status === 'processing' ? 'ring-2 ring-indigo-500 ring-offset-2 border-indigo-500' : 'border-slate-200'}
                                    ${img.status === 'success' ? 'border-green-200' : ''}
                                    ${img.status === 'error' ? 'border-red-200' : ''}
                                    active:cursor-grabbing hover:scale-[1.01] transition-transform duration-200
                                `}
                            >
                                {/* Drag Handle Indicator (Visual cue) */}
                                <div className="absolute top-2 right-2 z-10 p-1.5 bg-black/20 text-white rounded-md opacity-0 group-hover:opacity-100 cursor-grab">
                                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                                      <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 6.75h16.5M3.75 12h16.5m-16.5 5.25h16.5" />
                                    </svg>
                                </div>

                                {/* Remove Button */}
                                <button 
                                    onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                                    className="absolute top-2 left-2 z-10 bg-white/80 hover:bg-red-50 text-slate-400 hover:text-red-500 p-1.5 rounded-full backdrop-blur-sm transition-colors opacity-0 group-hover:opacity-100"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                                        <path d="M6.28 5.22a.75.75 0 00-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 101.06 1.06L10 11.06l3.72 3.72a.75.75 0 101.06-1.06L11.06 10l3.72-3.72a.75.75 0 00-1.06-1.06L10 8.94 6.28 5.22z" />
                                    </svg>
                                </button>

                                {/* Order Badge */}
                                <div className="absolute bottom-2 left-2 z-10 bg-slate-900/50 text-white text-[10px] px-1.5 py-0.5 rounded backdrop-blur-sm">
                                    #{index + 1}
                                </div>

                                {/* Image Aspect Ratio Box */}
                                <div className="aspect-[3/2] w-full bg-slate-100 relative overflow-hidden">
                                    <img src={img.previewUrl} alt="preview" className="w-full h-full object-cover pointer-events-none" />

                                    {/* Overlay Status */}
                                    <div className="absolute inset-0 flex items-center justify-center bg-black/20 group-hover:bg-black/10 transition-colors">
                                        {img.status === 'processing' && (
                                            <div className="bg-white/90 p-2 rounded-full shadow-lg">
